def token_case(s):
    exception_list = ['URL', 'ID']
    tokens = s.split('_')
    camel_cased_tokens = [tokens[0].lower()]

    for i in range(1, len(tokens)):
        if tokens[i] in exception_list:
            camel_cased_tokens.append(tokens[i])
        else:
            camel_cased_tokens.append(tokens[i].capitalize())

    return ''.join(camel_cased_tokens)
